namespace sv_93717c03b4904944a7e06ccba6301828.Services;

/// <summary>
/// Per-circuit state that tracks the currently selected warehouse.
/// Registered as Scoped so each SignalR circuit (user session) gets its own instance.
/// </summary>
public sealed class WarehouseState
{
    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
    [
        ("WH-A", "Warehouse A"),
        ("WH-B", "Warehouse B"),
        ("WH-C", "Warehouse C"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId)
            return;

        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_93717c03b4904944a7e06ccba6301828.Services;

/// <summary>
/// Per-circuit service that simulates querying a database for low-stock items
/// and broadcasts updated counts to all subscribed components.
/// </summary>
public sealed class InventoryAlertService
{
    private readonly Random _random = new();

    public int LatestLowStockCount { get; private set; }

    /// <summary>
    /// Fired after <see cref="RefreshAsync"/> completes, so every subscriber
    /// (sidebar badge, dashboard panel, etc.) can re-render.
    /// </summary>
    public event Action? OnAlertCountChanged;

    /// <summary>
    /// Simulates a database query — returns a random count between 0 and 15.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Fetches a new count for the given warehouse and notifies all subscribers.
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        LatestLowStockCount = await GetLowStockCountAsync(warehouseId);
        OnAlertCountChanged?.Invoke();
    }
}

@rendermode InteractiveServer
@using sv_93717c03b4904944a7e06ccba6301828.Services
@inject WarehouseState WarehouseState
@implements IDisposable

<div class="warehouse-selector">
    <label class="warehouse-label" for="warehouseSelect">Site:</label>
    <select id="warehouseSelect"
            class="form-select form-select-sm"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var (id, name) in WarehouseState.AvailableWarehouses)
        {
            <option value="@id">@name</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += StateHasChanged;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var selected = e.Value?.ToString();
        if (!string.IsNullOrEmpty(selected))
        {
            WarehouseState.SetWarehouse(selected);
        }
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= StateHasChanged;
    }
}

@rendermode InteractiveServer
@using sv_93717c03b4904944a7e06ccba6301828.Services
@inject InventoryAlertService AlertService
@implements IDisposable

@if (AlertService.LatestLowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill">@AlertService.LatestLowStockCount</span>
}
else
{
    <span class="badge bg-success rounded-pill">0</span>
}

@code {
    protected override void OnInitialized()
    {
        AlertService.OnAlertCountChanged += OnCountChanged;
    }

    private void OnCountChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= OnCountChanged;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@using sv_93717c03b4904944a7e06ccba6301828.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="text-muted">Viewing: <strong>@WarehouseState.CurrentWarehouseName</strong></p>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card @(AlertService.LatestLowStockCount > 0 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="display-4 @(AlertService.LatestLowStockCount > 0 ? "text-danger" : "text-success")">
                    @AlertService.LatestLowStockCount
                </p>
                <p class="text-muted">items below minimum level</p>
            </div>
        </div>
    </div>
    <div class="col-md-8">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Polling Status</h5>
                <ul class="list-unstyled mb-0">
                    <li>⏱️ Refresh interval: <strong>10 seconds</strong></li>
                    <li>📡 Polling: <strong class="text-success">Active</strong></li>
                    <li>🏭 Warehouse: <strong>@WarehouseState.CurrentWarehouseId</strong></li>
                </ul>
            </div>
        </div>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        AlertService.OnAlertCountChanged += OnAlertCountChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await StartPollingAsync();
        }
    }

    private async void OnWarehouseChanged()
    {
        // Restart polling for the new warehouse immediately
        await RestartPollingAsync();
        await InvokeAsync(StateHasChanged);
    }

    private void OnAlertCountChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private async Task StartPollingAsync()
    {
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        // Fetch immediately on start
        await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);

        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        try
        {
            while (await timer.WaitForNextTickAsync(token))
            {
                await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose or warehouse change
        }
    }

    private async Task RestartPollingAsync()
    {
        await CancelPollingAsync();
        await StartPollingAsync();
    }

    private Task CancelPollingAsync()
    {
        if (_cts is not null)
        {
            _cts.Cancel();
            _cts.Dispose();
            _cts = null;
        }
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        AlertService.OnAlertCountChanged -= OnAlertCountChanged;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

