@rendermode InteractiveServer
@using sv_93717c03b4904944a7e06ccba6301828.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="text-muted">Viewing: <strong>@WarehouseState.CurrentWarehouseName</strong></p>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card @(AlertService.LatestLowStockCount > 0 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="display-4 @(AlertService.LatestLowStockCount > 0 ? "text-danger" : "text-success")">
                    @AlertService.LatestLowStockCount
                </p>
                <p class="text-muted">items below minimum level</p>
            </div>
        </div>
    </div>
    <div class="col-md-8">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Polling Status</h5>
                <ul class="list-unstyled mb-0">
                    <li>⏱️ Refresh interval: <strong>10 seconds</strong></li>
                    <li>📡 Polling: <strong class="text-success">Active</strong></li>
                    <li>🏭 Warehouse: <strong>@WarehouseState.CurrentWarehouseId</strong></li>
                </ul>
            </div>
        </div>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;

    protected override void OnInitialized()
    {
        WarehouseState.OnChange += OnWarehouseChanged;
        AlertService.OnAlertCountChanged += OnAlertCountChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await StartPollingAsync();
        }
    }

    private async void OnWarehouseChanged()
    {
        // Restart polling for the new warehouse immediately
        await RestartPollingAsync();
        await InvokeAsync(StateHasChanged);
    }

    private void OnAlertCountChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private async Task StartPollingAsync()
    {
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        // Fetch immediately on start
        await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);

        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        try
        {
            while (await timer.WaitForNextTickAsync(token))
            {
                await AlertService.RefreshAsync(WarehouseState.CurrentWarehouseId);
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose or warehouse change
        }
    }

    private async Task RestartPollingAsync()
    {
        await CancelPollingAsync();
        await StartPollingAsync();
    }

    private Task CancelPollingAsync()
    {
        if (_cts is not null)
        {
            _cts.Cancel();
            _cts.Dispose();
            _cts = null;
        }
        return Task.CompletedTask;
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= OnWarehouseChanged;
        AlertService.OnAlertCountChanged -= OnAlertCountChanged;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

